#!/usr/bin/env node
// Embeds the platform-specific better_sqlite3.node binary as base64 into
// src/native-bundle.js so @yao-pkg/pkg can bundle it via src/**/*.js.
// pkg.assets globs are broken for node20 targets, so native .node files are
// handled the same way as other assets: embedded in JS then extracted at
// runtime by src/native-loader.js.
//
// This file is generated at build time and is NOT committed to the repo
// (see .gitignore). Each platform and Node ABI produces its own bundle.
//
// Run: node scripts/generate-native-bundle.js

'use strict';

const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

const ROOT = path.resolve(__dirname, '..');
const NODE_FILE = path.join(ROOT, 'node_modules', 'better-sqlite3', 'build', 'Release', 'better_sqlite3.node');
const OUTPUT = path.join(ROOT, 'src', 'native-bundle.js');

if (!fs.existsSync(NODE_FILE)) {
  console.error('ERROR: better_sqlite3.node not found. Run npm install (or npm rebuild better-sqlite3) first.');
  process.exit(1);
}

try {
  const Database = require('better-sqlite3');
  const db = new Database(':memory:');
  db.close();
} catch (err) {
  console.error(
    `ERROR: better-sqlite3 cannot load under Node ${process.version} (ABI ${process.versions.modules}).`,
  );
  console.error('Rebuild dependencies with this same Node runtime before packaging.');
  console.error(`Native load error: ${err.message}`);
  process.exit(1);
}

const data = fs.readFileSync(NODE_FILE);
const b64 = data.toString('base64');
const hash = crypto.createHash('sha256').update(data).digest('hex');
const size = (data.length / 1024).toFixed(0);

const content = [
  '// AUTO-GENERATED by scripts/generate-native-bundle.js. Do not edit by hand.',
  '// Platform-specific better_sqlite3 native binary, embedded as base64.',
  '// NOT committed to the repo (gitignored). Regenerated on each platform build.',
  '',
  '\'use strict\';',
  '',
  'module.exports = {',
  `  data: Buffer.from(${JSON.stringify(b64)}, 'base64'),`,
  `  sha256: ${JSON.stringify(hash)},`,
  `  platform: ${JSON.stringify(process.platform)},`,
  `  arch: ${JSON.stringify(process.arch)},`,
  `  moduleAbi: ${JSON.stringify(process.versions.modules)},`,
  `  nodeVersion: ${JSON.stringify(process.version)},`,
  '};',
  '',
].join('\n');

fs.writeFileSync(OUTPUT, content, 'utf8');
console.log(
  `Generated ${OUTPUT} (${size} KB ${process.platform}/${process.arch} ABI ${process.versions.modules} native binary).`,
);
